// E.164 form for tel: links (Iran +98).
export const phoneToE164 = (raw: string): string => {
  const digits = raw.replace(/\D/g, '');
  if (digits.startsWith('0')) return `+98${digits.slice(1)}`;
  if (digits.startsWith('98')) return `+${digits}`;
  return `+${digits}`;
};
